function getGovernedSheetInsertIndex_(ss, sheetName) {
  ss = ss || SpreadsheetApp.getActiveSpreadsheet();
  const targetName = String(sheetName || "").trim();
  const targetRank = getGlobalSheetSortRankByName_(targetName);
  let maxAllowedIndex = ss.getNumSheets() + 1;
  if (targetRank < 150) {
    const timingSheet = ss.getSheetByName("Framework Timing Report") || ss.getSheetByName(RFF_TIMING_SHEET);
    if (timingSheet) maxAllowedIndex = timingSheet.getIndex();
  }
  let targetIndex = targetRank > 20 ? 3 : 1;
  ss.getSheets().forEach(function(sheet) {
    const name = String(sheet.getName() || "").trim();
    if (!name || name === targetName) return;
    const rank = getGlobalSheetSortRankByName_(name);
    if (rank < targetRank) targetIndex = Math.max(targetIndex, sheet.getIndex() + 1);
    if (rank === targetRank && compareSheetNamesByGlobalOrder_(name, targetName) < 0) {
      targetIndex = Math.max(targetIndex, sheet.getIndex() + 1);
    }
  });
  return Math.max(1, Math.min(targetIndex, maxAllowedIndex));
}

