function parseReportMonthInput_(value) {
  const text = String(value || "").trim().toLowerCase();
  if (!text) throw new Error("Report month is required.");


  const numeric = Number(text);
  if (!isNaN(numeric) && numeric >= 1 && numeric <= 12) {
    return Math.floor(numeric);
  }


  const monthNames = {
    jan: 1, january: 1,
    feb: 2, february: 2,
    mar: 3, march: 3,
    apr: 4, april: 4,
    may: 5,
    jun: 6, june: 6,
    jul: 7, july: 7,
    aug: 8, august: 8,
    sep: 9, sept: 9, september: 9,
    oct: 10, october: 10,
    nov: 11, november: 11,
    dec: 12, december: 12
  };


  if (monthNames[text]) return monthNames[text];


  throw new Error("Invalid report month: " + text + ". Enter 1-12 or a month name.");
}

function promptForLockedYearReportMonth_(processTitle) {
  const ui = SpreadsheetApp.getUi();
  const response = ui.prompt(
    processTitle || "Report Month",
    "Enter report month. Examples: 05.26, July 2026, or 05/01/26.",
    ui.ButtonSet.OK_CANCEL
  );
  if (response.getSelectedButton() !== ui.Button.OK) return null;
  const text = String(response.getResponseText() || "").trim();
  if (!text) {
    notify_("Report month is required.");
    return null;
  }
  let reportDate = null;
  try {
    if (/^(\d{1,2}|[A-Za-z]+)$/.test(text)) {
      const month = parseReportMonthInput_(text);
      const year = new Date().getFullYear();
      reportDate = createLocalDateOnly_(year, month - 1, 1);
    } else {
      const numeric = text.match(/^(\d{1,2})[\.\/-](\d{2}|\d{4})$/);
      if (numeric) {
        const month = Number(numeric[1]);
        if (month < 1 || month > 12) throw new Error("Invalid report month: " + text + ". Enter a month from 1-12.");
        let year = Number(numeric[2]);
        if (year < 100) year += 2000;
        reportDate = createLocalDateOnly_(year, month - 1, 1);
      } else {
        reportDate = coerceToValidDate_(text);
      }
    }
  } catch (err) {
    notify_(err.message);
    return null;
  }

  if (!reportDate || isNaN(reportDate.getTime())) {
    notify_("Invalid report month: " + text + ". Enter 1-12, a month name, MM.YY, or a date in the target month.");
    return null;
  }

  return getMonthDateParts_(reportDate);
}

