  if (name.indexOf("cp due") !== -1 || name.indexOf("care plan due") !== -1) return SHEET_TYPE.CARE_PLAN_DUE;
  if (name.indexOf("unlock") !== -1) return SHEET_TYPE.UNLOCKED;
  if (name.indexOf("banner") !== -1) return SHEET_TYPE.BANNER;
