function applyDashboardSortOrderAlternatingColors_(sheet) {
  sheet = sheet || SpreadsheetApp.getActiveSheet();
  if (!sheet) return;
  const lastRow = sheet.getLastRow();
  const lastCol = sheet.getLastColumn();
  if (lastRow < DATA_START_ROW || lastCol < 1) return;
  const headers = getHeaders_(sheet, HEADER_ROW);
  const primarySortIdx = headers.indexOf("Primary Row Sort Order");
  const sortIdx = headers.indexOf("Sort Order");
  if (primarySortIdx === -1 && sortIdx === -1) return;
  const sheetType = getSheetTypeForOrganization_(sheet.getName());
  const dashboard = loadDashboardConfig_();
  const globals = dashboard.globals || {};
  const sheetDef = getSheetDefinitionByType_(dashboard, sheetType);
  const theme = getThemeColorsFromBase_((sheetDef && sheetDef.baseColor) || "#7665CC", globals);
  const dataRowCount = lastRow - DATA_START_ROW + 1;
  const dataRange = sheet.getRange(DATA_START_ROW, 1, dataRowCount, lastCol);
  const primarySortValues = primarySortIdx !== -1
    ? sheet.getRange(DATA_START_ROW, primarySortIdx + 1, dataRowCount, 1).getValues()
    : null;
  const sortValues = sortIdx !== -1
    ? sheet.getRange(DATA_START_ROW, sortIdx + 1, dataRowCount, 1).getValues()
    : null;
  const backgrounds = [];
  for (let i = 0; i < dataRowCount; i++) {
    const rawPrimarySort = primarySortValues ? primarySortValues[i][0] : "";
    const rawSort = sortValues ? sortValues[i][0] : "";
    let group = Number(rawPrimarySort);
    if (isNaN(group) || rawPrimarySort === "") {
      const sortNumber = Number(rawSort);
      group = isNaN(sortNumber) ? i : Math.floor(sortNumber);
    }
    backgrounds.push(new Array(lastCol).fill(group % 2 === 0 ? theme.level4 : "#FFFFFF"));
  }
  try {
    dataRange.setBackgrounds(backgrounds);
  } catch (err) {
    throw new Error("Alternating color application failed for " + sheet.getName() + ": " + err.message);
  }
}


function ensureStandardTitleRows_(sheet) {
