    enforceGlobalSheetSortOrder_(parsedMonth.monthParts);
    notify_(processName + " complete for " + parsedMonth.monthLabel + ". Hidden: " + result.hidden.length + "; Skipped: " + result.skipped.length + ".");
    return result;
  });
