function normalizeNumberFormatForCompare_(format) {
  let text = String(format || "")
    .trim()
    .toLowerCase()
    .replace(/\s+/g, "");


  text = text
    .replace(/\[\$-[^\]]+\]/g, "")
    .replace(/\[[^\]]+\]/g, "")
    .split(";")[0];

  if (/^m{1,2}\/d{1,2}\/yyyy$/.test(text)) return "date:mm/dd/yyyy";
  if (/^m{1,2}\/d{1,2}\/yy$/.test(text)) return "date:mm/dd/yy";
  if (/^m{1,2}\.d{1,2}\.yyyy$/.test(text)) return "date:mm.dd.yyyy";
  if (/^m{1,2}\.d{1,2}\.yy$/.test(text)) return "date:mm.dd.yy";

  return text;
}

function numberFormatsMatch_(actual, expected) {
  const a = normalizeNumberFormatForCompare_(actual);
  const e = normalizeNumberFormatForCompare_(expected);
  return a === e;
}

function validateTemplateFromDashboard_(dashboard, sheetDef, options) {
  options = options || {};
  const strict = !!options.strict;


  const ss = SpreadsheetApp.getActiveSpreadsheet();
  const sheet = ss.getSheetByName(sheetDef.templateName);
  const issues = [];
  const globals = dashboard.globals;
  const expectedHeaders = getHeadersForSheetType_(dashboard, sheetDef.sheetType);
  const behavior = getBehaviorForSheetType_(dashboard, sheetDef.sheetType);
  const colCount = Math.max(expectedHeaders.length, 4);
  const rowCount = resolveTemplateRowCount_(sheetDef, globals);
  const expectedSignature = normalizeTemplateFormatSignature_(buildTemplateFormatSignature_(dashboard, sheetDef, expectedHeaders, rowCount, colCount, behavior));


  if (!sheet) {
    return {
      templateName: sheetDef.templateName,
      sheetType: sheetDef.sheetType,
      status: "FAIL",
      issues: "Template missing"
    };
  }


  if (expectedHeaders.length === 0) {
    issues.push("No headers defined in dashboard");
  }


  if (!strict) {
    try {
      const storedSignature = normalizeTemplateFormatSignature_(getStoredTemplateFormatSignature_(sheetDef) || getStoredTemplateFormatSignatureFromSheet_(sheet));
      if (storedSignature && storedSignature === expectedSignature && expectedHeaders.length > 0) {
        return {
          templateName: sheetDef.templateName,
          sheetType: sheetDef.sheetType,
          status: "PASS",
          issues: "OK"
        };
      }


    } catch (err) {
      issues.push("Could not compare template signature: " + err.message);
    }
  }


  try {
    const frozenRows = sheet.getFrozenRows();
    const frozenColumns = sheet.getFrozenColumns();


    if (frozenRows !== globals.freezeRows) {
      issues.push("Frozen rows expected " + globals.freezeRows + " but found " + frozenRows);
    }


    if (expectedHeaders.length > 0 && frozenColumns > globals.freezeColumns) {
      issues.push("Frozen columns expected " + globals.freezeColumns + " or less but found " + frozenColumns);
    }
  } catch (err) {
    issues.push("Could not check frozen settings: " + err.message);
  }


  try {
    const actualHeaders = sheet.getRange(globals.headerRow, 1, 1, Math.max(expectedHeaders.length, 1))
      .getValues()[0]
      .map(normalizeHeader_);


    expectedHeaders.forEach(function(expected, index) {
      if (actualHeaders[index] !== expected) {
        issues.push("Header mismatch col " + (index + 1) + ": expected " + expected + ", found " + actualHeaders[index]);
      }
    });
  } catch (err) {
    issues.push("Could not check headers: " + err.message);
  }


  try {
    expectedHeaders.forEach(function(header, index) {
      const def = dashboard.columnDefinitions[header] || {};
      if (def.width && sheet.getColumnWidth(index + 1) !== def.width) {
        issues.push("Width mismatch for " + header);
      }
    });
  } catch (err) {
    issues.push("Could not check column widths: " + err.message);
  }


  try {
    const availableFormatRows = sheet.getMaxRows() - globals.dataStartRow + 1;
    if (availableFormatRows < 1) return issues;
    const sampleRows = Math.min(10, availableFormatRows);
    const formatWidth = Math.max(expectedHeaders.length, 1);
    const allFormats = sheet.getRange(globals.dataStartRow, 1, sampleRows, formatWidth).getNumberFormats();


    expectedHeaders.forEach(function(header, index) {
      const def = dashboard.columnDefinitions[header] || {};
      const expectedFormat = getExpectedNumberFormat_(def, globals);
      if (!expectedFormat) return;


      const expectedSheetsFormat = getGoogleSheetsNumberFormat_(expectedFormat, def.dateColumn);
      const mismatches = [];
      allFormats.forEach(function(row) {
        const actualFormat = row[index];
        if (!numberFormatsMatch_(actualFormat, expectedSheetsFormat)) {
          if (mismatches.indexOf(actualFormat) === -1) mismatches.push(actualFormat);
        }
      });


      if (mismatches.length > 0) {
        issues.push("Date/number format mismatch for " + header + " expected " + expectedFormat + " but found " + mismatches.join(", "));
      }
    });
  } catch (err) {
    issues.push("Could not check date/number formats: " + err.message);
  }


  try {
    if (behavior.usesFilter && !sheet.getFilter()) {
      issues.push("Filter missing");
    }
  } catch (err) {
    issues.push("Could not check filter: " + err.message);
  }


  return {
    templateName: sheetDef.templateName,
    sheetType: sheetDef.sheetType,
    status: issues.length === 0 ? "PASS" : "FAIL",
    issues: issues.length === 0 ? "OK" : issues.join("; ")
  };
}

function writeTemplateValidationReport_(results, options) {
  saveDashboardQualityRowsForTemplateValidation_(results, options);
  deleteLegacyQualityReportSheet_(RFF_VALIDATION_SHEET);
}


function formatRawData() {
  const sourceSheet = SpreadsheetApp.getActiveSheet();
  const monthParts = promptForLockedYearReportMonth_("Format Raw Data");
  if (!monthParts) return;


  const timing = startRuntimeTiming_("Format Raw Data", monthParts);


  try {
    const outputSheet = formatRawDataInPlaceSheet_(sourceSheet, monthParts, timing, markRuntimeStep_);
    writeRuntimeTimingReport_(timing);


    notify_(
      "Raw Data formatted in place as " + outputSheet.getName() + ".\n" +
      "Imported Raw Data columns and values were retained on the source sheet.\n" +
      "Four title/header governance rows and approved framework columns were added when missing.\n" +
      "Primary PMR Row and Banner fields were added/populated. Run Process Demo P next when ready."
    );


    return outputSheet;
  } catch (err) {
    markRuntimeStep_(timing, "ERROR - " + err.message);
    writeRuntimeTimingReport_(timing);
    notifyErrorWithTiming_("Format Raw Data stopped: " + err.message);
    throw err;
  }
}

function formatRawDataInPlaceSheet_(sourceSheet, monthParts, timing, markStepFn) {
  if (!sourceSheet) {
    throw new Error("No active sheet found. Select the imported Raw Data sheet before running Format Raw Data.");
  }


  const ss = SpreadsheetApp.getActiveSpreadsheet();
  const dashboard = loadDashboardConfig_();
  const sheetDef = getSheetDefinitionByType_(dashboard, SHEET_TYPE.RAW_DATA);
  const outputName = buildRawDataSheetName_(monthParts);
  const sourceName = sourceSheet.getName();


  if (sourceName === sheetDef.templateName) {
    throw new Error("The active sheet is not a Raw Data import sheet. Select the imported Raw Data source sheet before formatting.");
  }


  const step = typeof markStepFn === "function" ? markStepFn : markRuntimeStep_;
  const context = buildRawDataInPlaceFormattingContext_(sourceSheet, dashboard, sheetDef, monthParts);
  step(timing, "Read Raw Data source in place without editing imported values | Rows: " + context.rawData.values.length);


  deleteSheetIfExists_(ss, outputName, sourceName, sheetDef.templateName);
  if (sourceSheet.getName() !== outputName) {
    sourceSheet.setName(outputName);
    step(timing, "Rename Raw Data import sheet in place: " + sourceName + " -> " + outputName);
  }


  const inPlaceResult = writeRawDataInPlaceTitleRowsAndAddedColumns_(sourceSheet, context, monthParts, timing, step);
  step(timing, "Wave 4 Raw Data in-place title/header/column work complete | Added columns: " + inPlaceResult.addedColumns.join(", "));


  step(timing, "Wave 4 Raw Data approved-sync columns start");
  const approvedColumnsWritten = processRawDataApprovedSyncColumns_(sourceSheet, monthParts, timing, step);
  step(timing, "Wave 4 Raw Data approved-sync columns complete | Changed column groups: " + approvedColumnsWritten);


  step(timing, "Wave 4 Raw Data banner-column sync start");
  const bannerRowsUpdated = syncRawDataBannerColumns_(sourceSheet, monthParts, timing, step);
  step(timing, "Wave 4 Raw Data banner-column sync complete | Rows updated: " + bannerRowsUpdated);


  step(timing, "Wave 4 Raw Data row-height lock start");
  lockFinalOutputRowHeights_(sourceSheet, "Raw Data");
  step(timing, "Wave 4 Raw Data row-height lock complete");
  step(timing, "Wave 4 Raw Data visibility policy start");
  applyOutputVisibilityPolicy_(sourceSheet, dashboard, sheetDef.sheetType, timing);
  step(timing, "Wave 4 Raw Data visibility policy complete");
  clearSheetRuntimeCachesForSheet_(sourceSheet);
  hideSheetIfNeeded_(sourceSheet, timing, "Hide Raw Data sheet after formatting: " + sourceSheet.getName());
  refreshIndexAfterSheetWorkflow_("Format Raw Data");
  ss.setActiveSheet(sourceSheet);
  return sourceSheet;
}

function buildRawDataInPlaceFormattingContext_(sourceSheet, dashboard, sheetDef, monthParts) {
  const headers = getHeadersForSheetType_(dashboard, sheetDef.sheetType);
  const rawData = getRawDataSourceDataForOutput_(sourceSheet);
  return {
    dashboard: dashboard,
    sheetDef: sheetDef,
    sourceSheet: sourceSheet,
    sourceName: sourceSheet.getName(),
    headers: headers,
    rawData: rawData,
    outputRows: mapRowsToHeaders_(rawData.values, rawData.headers, headers)
  };
}

function writeRawDataInPlaceTitleRowsAndAddedColumns_(sheet, context, monthParts, timing, markStepFn) {
  const dashboard = context.dashboard;
  const sheetDef = context.sheetDef;
  const globals = dashboard.globals || {};
  const theme = getThemeColorsFromBase_(sheetDef.baseColor, globals);
  const step = typeof markStepFn === "function" ? markStepFn : markRuntimeStep_;
  const originalHeaderRow = rawDataSourceHeaderRow_(sheet);
  step(timing, "Wave 4 Raw Data header row detection complete | Header row: " + originalHeaderRow);


  if (originalHeaderRow > HEADER_ROW) {
    throw new Error("In-place Raw Data formatting expected import headers on row 1 or row " + HEADER_ROW + "; found row " + originalHeaderRow + ". No imported data was changed.");
  }


  if (originalHeaderRow < HEADER_ROW) {
    sheet.insertRowsBefore(1, HEADER_ROW - originalHeaderRow);
    step(timing, "Wave 4 Raw Data title-row insert complete | Rows inserted: " + (HEADER_ROW - originalHeaderRow));
  } else {
    step(timing, "Wave 4 Raw Data title-row insert skipped");
  }


  const headerWidth = Math.max(sheet.getLastColumn(), 1);
  const existingHeaders = sheet.getRange(HEADER_ROW, 1, 1, headerWidth).getValues()[0]
    .map(function(header) { return String(header || "").trim(); });
  const headerSet = new Set(existingHeaders.filter(Boolean));
  const governedRawDataHeaders = getHeadersForSheetType_(dashboard, sheetDef.sheetType);


  const addedColumns = [];
  governedRawDataHeaders.forEach(function(header) {
    const cleanHeader = String(header || "").trim();
    if (!cleanHeader || headerSet.has(cleanHeader)) return;
    addedColumns.push(cleanHeader);
    headerSet.add(cleanHeader);
  });


  if (addedColumns.length) {
    const lastCol = Math.max(sheet.getLastColumn(), 1);
    if (sheet.getMaxColumns() < lastCol + addedColumns.length) {
      sheet.insertColumnsAfter(sheet.getMaxColumns(), lastCol + addedColumns.length - sheet.getMaxColumns());
    }
    sheet.getRange(HEADER_ROW, lastCol + 1, 1, addedColumns.length).setValues([addedColumns]);
    step(timing, "Wave 4 Raw Data approved-column append complete | Columns added: " + addedColumns.length);
  } else {
    step(timing, "Wave 4 Raw Data approved-column append skipped");
  }


  const finalWidth = Math.max(sheet.getLastColumn(), headerWidth + addedColumns.length, 1);
  const finalHeaders = sheet.getRange(HEADER_ROW, 1, 1, finalWidth).getValues()[0]
    .map(function(header) { return String(header || "").trim(); });


  step(timing, "Wave 4 Raw Data title/header formatting start | Width: " + finalWidth);
  applyTitleRows_(sheet, dashboard, sheetDef, theme, finalWidth);
  sheet.getRange("B2").setValue(monthParts.firstDay).setNumberFormat((globals.defaultDateFormat || "m/d/yy"));
  sheet.getRange("D2").setValue(monthParts.lastDay).setNumberFormat((globals.defaultDateFormat || "m/d/yy"));
  applyHeaderRow_(sheet, dashboard, sheetDef, finalHeaders, theme, finalWidth);
  step(timing, "Wave 4 Raw Data title/header formatting complete");


  try {
    sheet.setTabColor(sheetDef.baseColor || sheet.getTabColor());
  } catch (err) {
    logBestEffortWarning_("In-place Raw Data tab color skipped for " + sheet.getName() + ": " + err.message);
  }


  try {
    sheet.setFrozenRows(HEADER_ROW);
    step(timing, "Wave 4 Raw Data frozen rows set");
    const existingFilter = sheet.getFilter && sheet.getFilter();
    if (existingFilter) {
      existingFilter.remove();
      step(timing, "Wave 4 Raw Data filter removal complete");
    } else {
      step(timing, "Wave 4 Raw Data filter removal skipped - no existing filter");
    }
    const filterRows = Math.max(sheet.getMaxRows() - HEADER_ROW + 1, 1);
    sheet.getRange(HEADER_ROW, 1, filterRows, finalWidth).createFilter();
    step(timing, "Wave 4 Raw Data filter creation complete | Rows: " + filterRows + "; Columns: " + finalWidth);
  } catch (err) {
    logBestEffortWarning_("In-place Raw Data filter/freeze setup skipped for " + sheet.getName() + ": " + err.message);
  }


  clearSheetRuntimeCachesForSheet_(sheet);
  return {
    addedColumns: addedColumns,
    governedRawDataHeaders: governedRawDataHeaders,
    finalHeaders: finalHeaders
  };
}

