function applyUniversalFastCanvasFormatting_(sheet, dashboard, headers) {
  if (!sheet || !dashboard || !headers) return;
  const lastRow = sheet.getLastRow();
  if (lastRow < DATA_START_ROW) return;
  try {
    applyColumnWidths_(sheet, dashboard, headers);
    applyHiddenColumnSettings_(sheet, dashboard, headers);
    sheet.getRange(
      DATA_START_ROW,
      1,
      lastRow - DATA_START_ROW + 1,
      Math.max(sheet.getLastColumn(), 1)
    ).setWrapStrategy(SpreadsheetApp.WrapStrategy.CLIP);
  } catch (err) {
    throw new Error("Universal canvas formatting failed for " + sheet.getName() + ": " + err.message);
  }
}

function applyGovernedTextAndNumberFormats_(sheet, dashboard, headers, dataStartRow, rowCount) {
  if (!sheet || !headers || !headers.length) return;
  const globals = (dashboard && dashboard.globals) || {};
  const columnDefinitions = (dashboard && dashboard.columnDefinitions) || {};
  const startRow = Number(dataStartRow || DATA_START_ROW);
  const hasExplicitRowCount = rowCount !== undefined && rowCount !== null;
  const requestedRows = hasExplicitRowCount ? Number(rowCount || 0) : Number(sheet.getMaxRows() - startRow + 1);
  if (requestedRows < 1) return;
  const rows = requestedRows;
  const formatsByA1 = {};

  headers.forEach(function(header, index) {
    const columnDef = columnDefinitions[header] || {};
    let format = String(columnDef.numberFormat || "").trim();
    if (!format) {
      format = columnDef.dateColumn || isDateLikeHeader_(header) ? (globals.defaultDateFormat || "mm/dd/yyyy") : "@";
    }
    const column = index + 1;
    const rangeA1 = rowColToA1_(startRow, column) + ":" + rowColToA1_(startRow + rows - 1, column);
    if (!formatsByA1[format]) formatsByA1[format] = [];
    formatsByA1[format].push(rangeA1);
  });

  Object.keys(formatsByA1).forEach(function(format) {
    try {
      sheet.getRangeList(formatsByA1[format]).setNumberFormat(format);
    } catch (err) {
      throw new Error("Governed text/number format failed for " + sheet.getName() + " with format " + format + ": " + err.message);
    }
  });
}

function applyOutputVisibilityPolicy_(sheet, dashboard, sheetType, timing) {
  if (!sheet) return;
  const normalizedSheetType = normalizeDashboardSheetTypeKey_(sheetType);
  const behavior = getBehaviorForSheetType_(dashboard || loadDashboardConfig_(), normalizedSheetType) || {};
  const visibility = String(behavior.outputVisibility || "VISIBLE").trim().toUpperCase();
  if (visibility === "HIDDEN" || visibility === "HIDE") {
    hideSheetIfNeeded_(sheet, timing, "Hide governed output sheet: " + sheet.getName());
  } else {
    showSheetIfNeeded_(sheet, timing, "Show governed output sheet: " + sheet.getName());
  }
}

function createOutputSheetFromDashboardTemplate_(sheetType, outputName, outputRows, firstDay, endDate, timing, timingLabel) {
  const ss = SpreadsheetApp.getActiveSpreadsheet();
  const dashboard = loadDashboardConfig_();
  const normalizedSheetType = normalizeDashboardSheetTypeKey_(sheetType);
  const sheetDef = getSheetDefinitionByType_(dashboard, normalizedSheetType);
  const headers = getHeadersForSheetType_(dashboard, normalizedSheetType);
  const template = ss.getSheetByName(sheetDef.templateName);
  const markCanvasStep = function(label) {
    if (timing) markFrameworkStep_(timing, String(timingLabel || "Dashboard fast canvas") + " - " + label + ": " + outputName);
  };

  if (!template) {
    throw new Error("Template not found: " + sheetDef.templateName + ". Run Create / Refresh All Templates first.");
  }

  deleteSheetIfExists_(ss, outputName, sheetDef.templateName);

  // 1. FAST CANVAS: Insert a perfectly blank sheet (zero overhead)
  const sheet = insertGovernedOutputSheet_(ss, outputName);
  showSheetIfNeeded_(sheet, timing, String(timingLabel || "Dashboard fast canvas") + " - sheet visibility enforced visible: " + outputName);
  markCanvasStep("blank sheet inserted in governed order");

  const width = Math.max(headers.length, 1);
  const rows = outputRows || [];
  const requiredRows = rows.length ? DATA_START_ROW + rows.length - 1 : DATA_START_ROW;

  // 2. RIGHT-SIZE GRID: Force dimensions before writing to save rendering ticks
  resizeSheetGrid_(sheet, requiredRows, width);
  markCanvasStep("grid resized to " + requiredRows + " rows x " + width + " cols");

  applyGovernedTextAndNumberFormats_(sheet, dashboard, headers, DATA_START_ROW, rows.length);
  markCanvasStep("governed text/date/number formats applied");

  // 3. NAKED WRITE: Set raw values instantly on unformatted cells
  if (rows.length) {
    sheet.getRange(DATA_START_ROW, 1, rows.length, width).setValues(rows.map(function(row) {
      const out = (row || []).slice(0, width);
      while (out.length < width) out.push("");
      return out;
    }));
  }
  markCanvasStep("raw values written | Rows: " + rows.length);

  // 4. BATCH PAINT: Copy top structures, headers, and grid formatting from Template
  try {
    template.getRange(1, 1, DATA_START_ROW - 2, width).copyTo(sheet.getRange(1, 1, DATA_START_ROW - 2, width));
    markCanvasStep("title rows copied from template");
    template.getRange(HEADER_ROW, 1, 1, width).copyTo(sheet.getRange(HEADER_ROW, 1, 1, width));
    markCanvasStep("header row copied from template");

    if (rows.length) {
      template.getRange(DATA_START_ROW, 1, 1, width)
        .copyTo(sheet.getRange(DATA_START_ROW, 1, rows.length, width), SpreadsheetApp.CopyPasteType.PASTE_FORMAT, false);
      markCanvasStep("data-row format copied from template | Rows: " + rows.length);
    } else {
      markCanvasStep("data-row format copy skipped - no rows");
    }

    // Explicitly stamp governed title text variables
    sheet.getRange("A1").setValue(sheetDef.reportTitle || normalizedSheetType || outputName);
    if (firstDay) sheet.getRange("B2").setValue(firstDay);
    if (endDate) sheet.getRange("D2").setValue(endDate);
    if (headers.length) sheet.getRange(HEADER_ROW, 1, 1, width).setValues([headers]);
    markCanvasStep("title/date/header values stamped");
  } catch (err) {
    throw new Error("Output style paint failed for " + outputName + ": " + err.message);
  }

  // 5. ENFORCE SYSTEM ENVIRONMENT: Set frozen attributes, filters, and color palettes
  try {
    sheet.setFrozenRows(template.getFrozenRows());
    sheet.setFrozenColumns(Math.min(template.getFrozenColumns(), width));
    sheet.setTabColor(template.getTabColor());
    markCanvasStep("frozen rows/columns and tab color applied");

    const existingFilter = sheet.getFilter && sheet.getFilter();
    if (existingFilter) existingFilter.remove();
    sheet.getRange(HEADER_ROW, 1, Math.max(sheet.getMaxRows() - HEADER_ROW + 1, 1), width).createFilter();
    markCanvasStep("filter created");
  } catch (err) {
    throw new Error("Environmental configurations failed for " + outputName + ": " + err.message);
  }

  applyUniversalFastCanvasFormatting_(sheet, dashboard, headers);
  markCanvasStep("universal canvas formatting applied");
  clearSheetRuntimeCachesForSheet_(sheet);
  markCanvasStep("runtime caches cleared");
  return sheet;
}

function createRawDataOutputSheetFromTemplateFast_(sheetType, outputName, outputRows, firstDay, endDate, sourceName) {
  const ss = SpreadsheetApp.getActiveSpreadsheet();
  const dashboard = loadDashboardConfig_();
  const normalizedSheetType = normalizeDashboardSheetTypeKey_(sheetType);
  const sheetDef = getSheetDefinitionByType_(dashboard, normalizedSheetType);
  const headers = getHeadersForSheetType_(dashboard, normalizedSheetType);
  const template = ss.getSheetByName(sheetDef.templateName);

  if (!template) {
    throw new Error("Template not found: " + sheetDef.templateName);
  }

  deleteSheetIfExists_(ss, outputName, sourceName, sheetDef.templateName);

  // 1. FAST CANVAS: Insert a perfectly blank sheet (zero overhead)
  const sheet = insertGovernedOutputSheet_(ss, outputName);
  showSheetIfNeeded_(sheet, null, null);

  const width = Math.max(headers.length, 1);
  const rows = outputRows || [];
  const requiredRows = rows.length ? DATA_START_ROW + rows.length - 1 : DATA_START_ROW;

  // 2. RIGHT-SIZE GRID: Force dimensions before writing to save rendering ticks
  resizeSheetGrid_(sheet, requiredRows, width);

  applyGovernedTextAndNumberFormats_(sheet, dashboard, headers, DATA_START_ROW, rows.length);

  // 3. NAKED WRITE: Set raw values instantly on unformatted cells (~2-3 seconds)
  if (rows.length) {
    sheet.getRange(DATA_START_ROW, 1, rows.length, width).setValues(rows.map(function(row) {
      const out = (row || []).slice(0, width);
      while (out.length < width) out.push("");
      return out;
    }));
  }

  // 4. BATCH PAINT: Copy title structures, headers, and grid formatting from Template AFTER values exist.
  // STRICT BOUNDARY: template replication failures must stop the workflow.
  template.getRange(1, 1, DATA_START_ROW - 2, width).copyTo(sheet.getRange(1, 1, DATA_START_ROW - 2, width));
  template.getRange(HEADER_ROW, 1, 1, width).copyTo(sheet.getRange(HEADER_ROW, 1, 1, width));

  const rawDataFormatCopyLimit = 2500;
  if (rows.length > 0 && rows.length <= rawDataFormatCopyLimit) {
    template.getRange(DATA_START_ROW, 1, 1, width)
      .copyTo(sheet.getRange(DATA_START_ROW, 1, rows.length, width), SpreadsheetApp.CopyPasteType.PASTE_FORMAT, false);
  } else if (rows.length > rawDataFormatCopyLimit) {
    logBestEffortWarning_("Raw Data template data-row format copy skipped for " + outputName + " because row count " + rows.length + " exceeds " + rawDataFormatCopyLimit + "; governed formats were applied instead.");
  }

  sheet.getRange("A1").setValue(sheetDef.reportTitle || normalizedSheetType || outputName);
  if (firstDay) sheet.getRange("B2").setValue(firstDay);
  if (endDate) sheet.getRange("D2").setValue(endDate);
  if (headers.length) sheet.getRange(HEADER_ROW, 1, 1, width).setValues([headers]);

  // 5. ENFORCE SYSTEM ENVIRONMENT: Set frozen attributes, filters, and color palettes
  try {
    sheet.setFrozenRows(template.getFrozenRows());
    sheet.setFrozenColumns(Math.min(template.getFrozenColumns(), width));
    sheet.setTabColor(template.getTabColor());

    const existingFilter = sheet.getFilter && sheet.getFilter();
    if (existingFilter) existingFilter.remove();
    sheet.getRange(HEADER_ROW, 1, Math.max(sheet.getMaxRows() - HEADER_ROW + 1, 1), width).createFilter();
  } catch (err) {
    throw new Error("Raw Data environmental configurations failed for " + outputName + ": " + err.message);
  }

  applyUniversalFastCanvasFormatting_(sheet, dashboard, headers);
  clearSheetRuntimeCachesForSheet_(sheet);
  markCanvasStep("runtime caches cleared");
  return sheet;
}

function ensureOutputSheetHasFormattedRows_(sheet, requiredRows, width) {
  if (!sheet) return;

  requiredRows = Math.max(Number(requiredRows || 1), DATA_START_ROW);
  width = Math.max(Number(width || 1), 1);
  const currentRows = sheet.getMaxRows();

  if (currentRows >= requiredRows) {
    return;
  }

  const rowsToAdd = requiredRows - currentRows;
  sheet.insertRowsAfter(currentRows, rowsToAdd);

  if (RFF_OUTPUT_EXTEND_TEMPLATE_FORMATTING) {
    try {
      const batchChunk = 1000;
      let processed = 0;

      while (processed < rowsToAdd) {
        const chunk = Math.min(batchChunk, rowsToAdd - processed);
        sheet.getRange(DATA_START_ROW, 1, 1, width)
          .copyTo(sheet.getRange(currentRows + 1 + processed, 1, chunk, width), { formatOnly: true });
        processed += chunk;
      }
    } catch (err) {
      logBestEffortWarning_("Output template formatting extension skipped for " + sheet.getName() + ": " + err.message);
    }
  }
}



function syncRawDataBannerColumns_(rawSheet, monthParts, timing, markStepFn) {
  if (!rawSheet) return 0;
  const step = typeof markStepFn === "function" ? markStepFn : markRuntimeStep_;
  const bannerSheet = getCurrentBannersSheet_(monthParts);
  if (!bannerSheet) {
    logBestEffortWarning_("Raw Data Banner sync skipped: Banners sheet not found.");
    return 0;
  }


  const data = getDataValues_(rawSheet, HEADER_ROW, DATA_START_ROW);
  step(timing, "Wave 4 Raw Data banner-sync bulk read complete | Rows: " + data.values.length);
  if (!data.values.length) return 0;


  const rawHeaderMap = data.headerMap;
  const rawPMRIdx = getPMRIndex_(rawHeaderMap);
  const rawPrimaryPMRRowIdx = rawHeaderMap["Primary PMR Row"];
  const rawLastNameIdx = rawHeaderMap["Last Name"];
  const rawFirstNameIdx = rawHeaderMap["First Name"];
  if (rawPMRIdx === -1 || rawLastNameIdx === undefined || rawFirstNameIdx === undefined) {
    logBestEffortWarning_("Raw Data Banner sync skipped: missing Participant PMR#, Last Name, or First Name.");
    return 0;
  }


  const bannerMap = buildSourceMapByCompositeKeyForDemoPBanner_(
    bannerSheet,
    HEADER_ROW,
    DATA_START_ROW,
    ["Participant PMR#", "Last Name", "First Name"]
  );
  step(timing, "Wave 4 Raw Data banner-sync source map built | Keys: " + bannerMap.size);
  if (bannerMap.size === 0) return 0;


  const beforeValues = {};
  BANNER_SYNC_FIELDS.forEach(function(header) {
    const idx = rawHeaderMap[header];
    if (idx !== undefined) {
      beforeValues[idx] = data.values.map(function(row) { return row[idx]; });
    }
  });


  let updatedRows = 0;


  data.values.forEach(function(row) {
    if (rawPrimaryPMRRowIdx !== undefined && !isPrimaryPMRRowValue_(row[rawPrimaryPMRRowIdx])) return;


    const key = [
      normalizeKeyPart_(row[rawPMRIdx]),
      normalizeKeyPart_(row[rawLastNameIdx]),
      normalizeKeyPart_(row[rawFirstNameIdx])
    ].join("|||");
    const source = bannerMap.get(key);
    if (!source) return;


    let changed = false;
    BANNER_SYNC_FIELDS.forEach(function(field) {
      const targetIdx = rawHeaderMap[field];
      if (targetIdx === undefined) return;
      if (!Object.prototype.hasOwnProperty.call(source, field)) return;
      const newValue = source[field];
      const cleanOld = String(row[targetIdx] || "").trim().toUpperCase();
      const cleanNew = String(newValue || "").trim().toUpperCase();
      if (cleanOld !== cleanNew) {
        row[targetIdx] = newValue;
        changed = true;
      }
    });
    if (changed) updatedRows++;
  });


  if (updatedRows > 0) {
    const changedColumnGroups = writeChangedColumnsOnly_(rawSheet, data, beforeValues);
    step(timing, "Wave 4 Raw Data banner-sync guarded write complete | Changed column groups: " + changedColumnGroups);
    clearSheetRuntimeCachesForSheet_(rawSheet);
  } else {
    step(timing, "Wave 4 Raw Data banner-sync guarded write skipped - no changed rows");
  }
  return updatedRows;
}

function buildSourceMapByCompositeKeyForDemoPBanner_(sheet, headerRow, dataStartRow, keyHeaders) {
  const lastRow = sheet.getLastRow();
  const lastCol = sheet.getLastColumn();
  const map = new Map();


  if (lastRow < dataStartRow || lastCol < 1) return map;


  const headers = getHeaders_(sheet, headerRow);
  const headerMap = buildHeaderIndexMap_(headers);


  if (keyHeaders.some(header => headerMap[header] === undefined)) return map;


  const data = sheet.getRange(dataStartRow, 1, lastRow - dataStartRow + 1, lastCol).getValues();


  data.forEach(row => {
    const key = keyHeaders
      .map(header => normalizeKeyPart_(row[headerMap[header]]))
      .join("|||");


    if (key.replace(/\|/g, "") === "") return;


    const record = {};
    headers.forEach((header, idx) => {
      if (header) record[header] = row[idx];
    });


    map.set(key, record);
  });


  return map;
}


