}

function flattenDemoPContactRowsInMemory_(data, requireIntegrity) {
  if (!data || !data.values || !data.values.length) return 0;
  const headerMap = data.headerMap || buildHeaderIndexMap_(data.headers || []);
  const pmrIdx = getPMRIndex_(headerMap);
  const primaryIdx = headerMap["Primary PMR Row"];
  if (pmrIdx === -1 || primaryIdx === undefined) throw new Error("Demo P in-memory flat-record compression requires PMR and Primary PMR Row headers.");

  const contactTargets = ["Contact - 1", "Contact - 2", "Contact - 3", "Contact - 4", "Contact - 5", "Contact - 6", "Contact - 7", "Contact - 8"];
  const contactTargetIndexes = contactTargets.map(function(header) { return headerMap[header]; }).filter(function(idx) { return idx !== undefined; });
  const summaryIdx = headerMap["Contact - Summary"];
  const grouped = new Map();

  data.values.forEach(function(row, originalIndex) {
    const pmr = normalizePMR_(row[pmrIdx]);
    if (!pmr) return;
    if (!grouped.has(pmr)) grouped.set(pmr, []);
    grouped.get(pmr).push({ row: row, originalIndex: originalIndex });
  });

  const flatRows = [];
  let assignedContacts = 0;
  grouped.forEach(function(items, pmr) {
    let primaryItem = items.find(function(item) { return isPrimaryPMRRowValue_(item.row[primaryIdx]); }) || items[0];
    const output = primaryItem.row.slice();
    const summaries = [];

    items.forEach(function(item) {
      if (item === primaryItem) return;
      const summary = buildDemoPContactSummaryForFlatRecord_(item.row, headerMap);
      if (!summary) return;
      summaries.push(summary);
      assignedContacts++;
    });

    summaries.slice(0, contactTargetIndexes.length).forEach(function(summary, idx) {
      const targetIdx = contactTargetIndexes[idx];
      if (targetIdx !== undefined && normalizeCompareValue_(output[targetIdx]) === "") output[targetIdx] = summary;
    });
    if (summaryIdx !== undefined && summaries.length && normalizeCompareValue_(output[summaryIdx]) === "") {
      output[summaryIdx] = summaries.join("\n");
    }
    flatRows.push(output);
    grouped.set(pmr, null);
  });

  if (requireIntegrity && assignedContacts > 0 && contactTargetIndexes.length === 0) {
    throw new Error("Contact flattening integrity check failed: no Contact - 1..8 target columns are available.");
  }

  sortDemoPFlatRows_(flatRows, headerMap);
  data.values = flatRows;
  return flatRows.length;
}

function buildDemoPContactSummaryForFlatRecord_(row, headerMap) {
  const parts = [
    "Contact - First Name",
    "Contact - Last Name",
    "Relationship",
    "Type of Contact",
    "Contact - Primary Language",
    "AD1 - Phone",
    "AD2 - Phone",
    "AD3 - Phone",
    "Company",
    "Contact - Notes"
  ].map(function(header) {
    const idx = headerMap[header];
    return idx === undefined ? "" : String(row[idx] || "").trim();
  }).filter(Boolean);
  return parts.join(" | ");
}

function sortDemoPFlatRows_(rows, headerMap) {
  const lastIdx = headerMap["Last Name"];
  const firstIdx = headerMap["First Name"];
  const nameIdx = headerMap["Name"];
  rows.sort(function(a, b) {
    const aKey = String((lastIdx !== undefined ? a[lastIdx] : "") || (nameIdx !== undefined ? a[nameIdx] : "") || "").toLowerCase();
    const bKey = String((lastIdx !== undefined ? b[lastIdx] : "") || (nameIdx !== undefined ? b[nameIdx] : "") || "").toLowerCase();
    if (aKey !== bKey) return aKey.localeCompare(bKey);
    const aFirst = String(firstIdx !== undefined ? a[firstIdx] || "" : "").toLowerCase();
    const bFirst = String(firstIdx !== undefined ? b[firstIdx] || "" : "").toLowerCase();
    return aFirst.localeCompare(bFirst);
  });
}

function processDemoP() {
  const monthParts = promptForLockedYearReportMonth_("Process Demo P");
  if (!monthParts) return;


  const timing = startRuntimeTiming_("Process Demo P", monthParts);
  let movedResult = {
    pmrsRemoved: 0,
    rowsRemoved: 0,
    rowsCopied: 0
  };


  try {
    const buildResult = getOrCreateDemoPProcessingSheet_(monthParts, timing);
    const sheet = buildResult && buildResult.sheet ? buildResult.sheet : buildResult;


    if (buildResult && buildResult.movedResult) {
      movedResult = buildResult.movedResult;
    }


    ensureStandardTitleRows_(sheet);
    markRuntimeStep_(timing, "Prepare Demo P title/header rows");


    clearSheetRuntimeCachesForSheet_(sheet);
    markRuntimeStep_(timing, "Demo P strict header verification skipped - dashboard schema mapping already applied in memory");


    if (buildResult && buildResult.preProcessedWorkingSource) {
      markRuntimeStep_(timing, "Demo P Working Source processing skipped - already completed in optimized Raw Data single-pass build");
    } else {
      processDemoPAsWorkingSource_(sheet, monthParts, timing, sheet.getName(), buildResult && buildResult.sourceWasRawData ? "Created" : "Updated");
      markRuntimeStep_(timing, "Demo P working-source processing complete; disenrolled rows retained for Disenrolled List workflow");
    }

    if (buildResult && buildResult.createdFromDashboardTemplate) {
      markRuntimeStep_(timing, "Apply Demo P dashboard template formatting skipped - template copy already formatted");
    } else {
      applyDemoPTemplateToSheet_(sheet, monthParts);
      markRuntimeStep_(timing, "Apply Demo P dashboard template formatting");
    }


    setUniqueSheetName_(sheet, DEMO_P_PREFIX);
    markRuntimeStep_(timing, "Maintain ongoing Demo P sheet name");


    lockFinalOutputRowHeights_(sheet, "Demo P");
    markRuntimeStep_(timing, "Lock Demo P final row heights");

    const trimmedDemoRows = trimExcessRows_(sheet, 1000);
    markRuntimeStep_(timing, "Trim Demo P excess blank rows", "Rows removed: " + trimmedDemoRows);

    writeRuntimeTimingReport_(timing);


    notify_(
      "Demo P processed as the working source.\n" +
      "Raw Data preserved when source sheet was Raw Data.\n" +
      "Demo P contains all Raw Data rows, including disenrolled participants.\n" +
      "Disenrolled PMRs excluded from Demo P: " + movedResult.pmrsRemoved + "\n" +
      "Disenrolled primary rows copied to exclusion list: " + movedResult.rowsCopied + "\n" +
      "Contact, phone, address, language, notes, banner, and Primary PMR fields were processed on Demo P.\n" +
      "Care Plan Due and Unlocked Care Plan remain Master List sync functions.\n" +
      "Master List can now be created from Primary PMR rows only."
    );


    return sheet;
  } catch (err) {
    markRuntimeStep_(timing, "ERROR - " + err.message);
    writeRuntimeTimingReport_(timing);
    notifyErrorWithTiming_("Process Demo P stopped: " + err.message);
    throw err;
  }
}

function processDemoPAsWorkingSource_(sheet, monthParts, timing, sourceSheetName, status) {
  markRuntimeStep_(timing, "Demo P Working Source - strict header verification skipped; dashboard schema mapping already applied");

  const data = getDataValues_(sheet, HEADER_ROW, DATA_START_ROW);
