function buildMonthlyChangeReportForMonth_(monthParts, timing) {
  if (!monthParts) return null;


  const ss = SpreadsheetApp.getActiveSpreadsheet();
  const currentDemo = getCurrentRawDataSheet_(monthParts);
  const previousDemo = getPreviousRawDataSheet_(monthParts);


  if (!currentDemo) {
    notify_(
      "Current month Raw Data was not found.\n\n" +
      `Expected current month start date: ${formatDateForSheetName_(monthParts.firstDay)}\n` +
      "Example accepted name:\n" +
      `Raw Data ${formatDateForSheetName_(monthParts.firstDay)} - ${formatDateForSheetName_(monthParts.lastDay)}`
    );
    return null;
  }


  if (!previousDemo) {
    notify_(
      "Previous month Raw Data was not found.\n\n" +
      "The Monthly Change Report compares previous month Raw Data to current month Raw Data.\n\n" +
      `Current source found: ${currentDemo.getName()}\n` +
      `Expected previous month start date: ${formatDateForSheetName_(monthParts.previousMonthFirstDay)}\n` +
      "Example accepted name:\n" +
      `Raw Data ${formatDateForSheetName_(monthParts.previousMonthFirstDay)} - ${formatDateForSheetName_(monthParts.previousMonthLastDay)}`
    );
    return null;
  }




  markRuntimeStep_(timing, "Monthly Change detail - source sheets located | Current: " + currentDemo.getName() + "; Previous: " + previousDemo.getName());
  const sectionData = compareRawDemoPForSectionReport_(previousDemo, currentDemo, monthParts);
  markRuntimeStep_(timing, "Monthly Change datasets compiled in-memory", "Current rows: " + sectionData.currentData.values.length + "; Previous rows: " + sectionData.previousData.values.length + "; Current PMRs: " + sectionData.currentData.rowsByPMR.size + "; Previous PMRs: " + sectionData.previousData.rowsByPMR.size);
  const totalPMRs =
    sectionData.enrollmentPMRs.size +
    sectionData.disenrollmentPMRs.size +
    sectionData.demographicPMRs.size +
    sectionData.caseloadPMRs.size +
    sectionData.contactPMRs.size +
    sectionData.bannerPMRs.size +
    sectionData.otherPMRs.size;


  if (totalPMRs === 0) {
    notify_(
      "No Raw Data changes found. Monthly Change Report was not created.\n\n" +
      `Current source: ${currentDemo.getName()}\n` +
      `Previous source: ${previousDemo.getName()}\n\n` +
      `Current Raw Data rows read: ${sectionData.currentData.values.length}\n` +
      `Previous Raw Data rows read: ${sectionData.previousData.values.length}\n` +
      `Current PMRs found: ${sectionData.currentData.rowsByPMR.size}\n` +
      `Previous PMRs found: ${sectionData.previousData.rowsByPMR.size}\n\n` +
      "For enrollments, Capitation Date must equal the report date. " +
      "For disenrollments, Disenrollment Effective Date must be between the previous month first day and the report date."
    );
    return null;
  }


  const reportName = buildMonthlySheetName_(MONTHLY_CHANGE_REPORT_PREFIX, monthParts.firstDay, monthParts.lastDay);
  let reportSheet = ss.getSheetByName(reportName);


  if (reportSheet) {
    deleteSheetSafely_(ss, reportSheet, "Monthly Change report rebuild");
    markRuntimeStep_(timing, "Monthly Change detail - existing report sheet deleted: " + reportName);
  }


  const dashboard = loadDashboardConfig_();
  const sheetDef = getSheetDefinitionByType_(dashboard, SHEET_TYPE.MONTHLY_CHANGE);
  const template = ss.getSheetByName(sheetDef.templateName);
  if (!template) throw new Error("Template not found: " + sheetDef.templateName + ". Run Create / Refresh All Templates first.");
  reportSheet = template.copyTo(ss);
  markRuntimeStep_(timing, "Monthly Change detail - template copied: " + sheetDef.templateName);
  setUniqueSheetName_(reportSheet, reportName);
  positionSheetInGlobalSortOrder_(reportSheet);
  showSheetIfNeeded_(reportSheet, timing, "Monthly Change detail - report sheet shown");
  markRuntimeStep_(timing, "Monthly Change report sheet created from template in governed order");

  buildMonthlyChangeReportSectionLayout_(reportSheet, currentDemo, sectionData.currentData.headers, monthParts);
  markRuntimeStep_(timing, "Monthly Change section layout prepared");
  populateMonthlyChangeReportSections_(reportSheet, sectionData, monthParts);
  markRuntimeStep_(timing, "Monthly Change section rows populated");
  formatMonthlyChangeReportSectionSheet_(reportSheet, sectionData.currentData.headers);
  markRuntimeStep_(timing, "Monthly Change report drawn and subheaders formatted");

  setUniqueSheetName_(reportSheet, reportName);
  createIndexSheet();
  markRuntimeStep_(timing, "Monthly Change index refreshed");




notify_(
    "Monthly Change Report created.\n\n" +
    `Current source: ${currentDemo.getName()}\n` +
    `Previous source: ${previousDemo.getName()}\n\n` +
    `Enrollments: ${sectionData.enrollmentPMRs.size}\n` +
    `Disenrollments: ${sectionData.disenrollmentPMRs.size}\n` +
