function createMasterList() {
  const monthParts = promptForLockedYearReportMonth_("Create Master List");
  if (!monthParts) return;
  return createMasterListForMonth_(monthParts);
}

function createMasterListForMonth_(monthParts, parentTiming) {
  if (!monthParts) return null;
  const ss = SpreadsheetApp.getActiveSpreadsheet();
  const timing = parentTiming || startRuntimeTiming_("Create Master List", monthParts);
  const markStep = function(label, details) {
    if (parentTiming) {
      markFrameworkStep_(timing, "Create Monthly Update - Create Master List - " + label, details || "");
    } else {
      markRuntimeStep_(timing, label, details);
    }
  };
  let masterSheet = null;
  let copiedRowCount = 0;
  try {
    markStep("Start");
    const demoSheet = getCurrentDemoPSheet_(monthParts);
    markStep("Locate current processed Demo P sheet");
    if (!demoSheet) {
      notify_("Demo P sheet for that month was not found. Run Process Demo P first.");
      markStep("Stopped - missing Demo P");
      if (!parentTiming) writeRuntimeTimingReport_(timing);
      return null;
    }
    const masterName = buildMonthlySheetName_(MASTER_LIST_PREFIX, monthParts.firstDay, monthParts.lastDay);
    const existingMasterSheet = ss.getSheetByName(masterName);
    if (existingMasterSheet) {
      const ui = SpreadsheetApp.getUi();
      const response = ui.alert(
        "Master List Exists",
        `${masterName} already exists. Replace it?`,
        ui.ButtonSet.YES_NO
      );
      if (response !== ui.Button.YES) {
        notify_("Create Master List cancelled.");
        markStep("Cancelled - existing Master List not replaced");
        if (!parentTiming) writeRuntimeTimingReport_(timing);
        return null;
      }
    }
    const masterBuildName = existingMasterSheet ? buildStagedMasterListSheetName_(masterName) : masterName;
    masterSheet = createMasterListSheetFromTemplate_(ss, masterBuildName, monthParts, timing, parentTiming ? "Create Monthly Update - Create Master List - Canvas detail" : "Create Master List canvas detail");
    if (existingMasterSheet) {
      hideSheetIfNeeded_(masterSheet, timing, "Master List staged build hidden until validation: " + masterBuildName);
      markStep("Create hidden staged Master List canvas");
    } else {
      markStep("Create naked canvas - Master List output sheet");
    }
    buildMasterListHeadersBeforeDataCopy_(demoSheet, masterSheet);
    markStep("Build Master List headers");
    copiedRowCount = copyPrimaryDemoPRowsToMasterListByHeader_(demoSheet, masterSheet, monthParts);
    markStep("Copy Primary PMR rows from processed Demo P to Master List");
    trimOutputSheetToDataSize_(masterSheet, copiedRowCount || 0, SHEET_TYPE.MASTER_LIST);
    markStep("Right-size Master List output rows");
    const masterData = getDataValues_(masterSheet, HEADER_ROW, DATA_START_ROW);
    syncUnlockedCarePlanSourceIntoData_(masterData, monthParts, null);
    markStep("Sync Unlocked CP to Master List primary rows (in-memory)");
    syncCarePlanDueSourceIntoData_(masterData, monthParts, null);
    markStep("Sync Care Plan Due to Master List primary rows (in-memory)");
    if (masterData.range) masterData.range.setValues(masterData.values);
    markStep("Batch write Care Plan sync data to Master List");
    if (existingMasterSheet) {
      masterSheet = promoteStagedMasterListSheet_(ss, masterSheet, existingMasterSheet, masterName, copiedRowCount || 0, timing, markStep);
    } else {
      setUniqueSheetName_(masterSheet, masterName);
      markStep("Set final Master List sheet name");
    }
    lockFinalOutputRowHeights_(masterSheet, "Master List");
    markStep("Lock Master List final row heights");
    hideReportTemplates(null, timing);
    markStep("Hide report templates before Master List completion");
    if (!parentTiming) {
      writeRuntimeTimingReport_(timing);
      notify_(
        `Master List created. Copied ${copiedRowCount} Primary PMR row(s) from processed Demo P.\n\n` +
        `Runtime: ${formatSeconds_((new Date().getTime() - timing.startMs) / 1000)}`
      );
    }
    return masterSheet;
  } catch (err) {
    try {
      const failedMasterName = monthParts ? buildMonthlySheetName_(MASTER_LIST_PREFIX, monthParts.firstDay, monthParts.lastDay) : "";
      cleanupFailedStagedMasterListSheet_(ss, masterSheet, failedMasterName, timing, markStep);
    } catch (cleanupErr) {
      logBestEffortWarning_("Master List staged cleanup failed: " + cleanupErr.message);
    }
    if (parentTiming) {
      markFrameworkStep_(timing, "ERROR - Create Monthly Update - Create Master List - " + err.message, err && err.stack ? err.stack : "");
    } else {
      markRuntimeStep_(timing, "ERROR - " + err.message);
      try {
        writeRuntimeTimingReport_(timing);
      } catch (reportErr) {
        logBestEffortWarning_("Could not write timing report: " + reportErr.message);
      }
    }
    throw err;
  }
}

function copyPrimaryDemoPRowsToMasterListByHeader_(demoSheet, masterSheet, monthParts) {
  const demoData = getDataValues_(demoSheet, HEADER_ROW, DATA_START_ROW);
  if (!demoData.values.length) return 0;
  const demoHeaders = demoData.headers;
  const demoHeaderMap = demoData.headerMap;
  const masterHeaders = getHeaders_(masterSheet, HEADER_ROW);
  const masterHeaderMap = getHeaderMap_(masterSheet, HEADER_ROW);
  const pmrIdx = getPMRIndex_(demoHeaderMap);
  if (pmrIdx === -1) {
    throw new Error("Demo P is missing Participant PMR# / PMR # column.");
  }
  const primaryIdx = demoHeaderMap["Primary PMR Row"];
  const dobIdx = getDOBIndex_(demoHeaderMap);
  function getMasterTargetIndex_(header) {
    if (masterHeaderMap[header] !== undefined) return masterHeaderMap[header];
    const aliases = {
      "Participant PMR#": ["PMR #", "PMR#", "Participant PMR"],
      "PMR #": ["Participant PMR#", "PMR#", "Participant PMR"],
      "PMR#": ["Participant PMR#", "PMR #", "Participant PMR"],
      "Participant PMR": ["Participant PMR#", "PMR #", "PMR#"]
    };
    const candidates = aliases[header] || [];
    for (let i = 0; i < candidates.length; i++) {
      if (masterHeaderMap[candidates[i]] !== undefined) return masterHeaderMap[candidates[i]];
    }
    return undefined;
  }
  function buildOutputRows_(mode) {
    const output = [];
    const seenPMRs = new Set();
    demoData.values.forEach(row => {
      const pmr = normalizePMR_(row[pmrIdx]);
      if (!pmr) return;
      let includeRow = false;
      if (mode === "primary") {
        includeRow = primaryIdx !== undefined && isPrimaryPMRRowValue_(row[primaryIdx]);
      } else if (mode === "dob") {
        includeRow = dobIdx !== -1 && normalizeCompareValue_(row[dobIdx]) !== "" && !seenPMRs.has(pmr);
      } else if (mode === "first") {
        includeRow = !seenPMRs.has(pmr);
      }
      if (!includeRow) return;
      seenPMRs.add(pmr);
      const out = new Array(masterHeaders.length).fill("");
      demoHeaders.forEach((header, sourceIdx) => {
        if (!header) return;
        const targetIdx = getMasterTargetIndex_(header);
        if (targetIdx !== undefined) {
          out[targetIdx] = row[sourceIdx];
        }
      });
      output.push(out);
    });
    return output;
  }
  let output = buildOutputRows_("primary");


  if (output.length === 0) output = buildOutputRows_("dob");
  if (output.length === 0) output = buildOutputRows_("first");
  if (output.length > 0) {
    masterSheet.getRange(DATA_START_ROW, 1, output.length, masterHeaders.length).setValues(output);
    clearSheetRuntimeCachesForSheet_(masterSheet);
  }
  return output.length;
}

function createOrRefreshMasterListTemplate_(ss) {


  const dashboard = loadDashboardConfig_();
  const sheetDef = getSheetDefinitionByType_(dashboard, SHEET_TYPE.MASTER_LIST);
  return createOrRefreshTemplateFromDashboard_(dashboard, sheetDef, null);
}

function createMasterListSheetFromTemplate_(ss, targetName, monthParts, timing, timingLabel) {
  ss = ss || SpreadsheetApp.getActiveSpreadsheet();
  const prefix = String(timingLabel || "Master List canvas detail");
  const markCanvasStep = function(label, details) {
    if (timing) markFrameworkStep_(timing, prefix + " - " + label + ": " + targetName, details || "");
  };
  const existing = ss.getSheetByName(targetName);
  markCanvasStep("existing sheet lookup complete", existing ? "Existing sheet found" : "No existing sheet found");
  if (existing) {
    deleteSheetSafely_(ss, existing, "Master List canvas replacement", [RFF_BASE_TEMPLATE_NAME]);
    markCanvasStep("existing target sheet deleted after guard validation");
  }

  const dashboard = loadDashboardConfig_();
  markCanvasStep("dashboard configuration loaded");
  const sheetDef = getSheetDefinitionByType_(dashboard, SHEET_TYPE.MASTER_LIST);
  const headers = getHeadersForSheetType_(dashboard, SHEET_TYPE.MASTER_LIST);
  markCanvasStep("headers resolved | Columns: " + headers.length);
  const template = ss.getSheetByName(sheetDef.templateName);
  markCanvasStep("template lookup complete", sheetDef.templateName);
  if (!template) {
    throw new Error("Template not found: " + sheetDef.templateName + ". Run Create / Refresh Master List Template first.");
  }

  const width = Math.max(headers.length, 1);
  const requiredRows = Math.max(template.getMaxRows(), DATA_START_ROW);

  const sheet = insertGovernedOutputSheet_(ss, targetName);
  markCanvasStep("blank governed sheet inserted in governed order", "Required rows: " + requiredRows + "; Columns: " + width);
  showSheetIfNeeded_(sheet, timing, prefix + " - sheet visibility enforced visible: " + targetName);
  resizeSheetGrid_(sheet, requiredRows, width);
  markCanvasStep("grid resized", "Rows: " + requiredRows + "; Columns: " + width);

  try {
    template.getRange(1, 1, DATA_START_ROW - 2, width)
      .copyTo(sheet.getRange(1, 1, DATA_START_ROW - 2, width));
    markCanvasStep("title rows copied from template");
    template.getRange(HEADER_ROW, 1, 1, width)
      .copyTo(sheet.getRange(HEADER_ROW, 1, 1, width));
    markCanvasStep("header row copied from template");
    if (requiredRows >= DATA_START_ROW) {
      template.getRange(DATA_START_ROW, 1, 1, width)
        .copyTo(
          sheet.getRange(DATA_START_ROW, 1, requiredRows - DATA_START_ROW + 1, width),
          SpreadsheetApp.CopyPasteType.PASTE_FORMAT,
          false
        );
      markCanvasStep("data-row format copied from template", "Rows formatted: " + (requiredRows - DATA_START_ROW + 1));
    } else {
      markCanvasStep("data-row format copy skipped - no data rows");
    }
  } catch (err) {
    logBestEffortWarning_("Master List naked canvas style paint skipped: " + err.message);
  }
  applyColumnWidths_(sheet, dashboard, headers);
  markCanvasStep("column widths applied");
  applyGovernedTextAndNumberFormats_(sheet, dashboard, headers, DATA_START_ROW, requiredRows >= DATA_START_ROW ? requiredRows - DATA_START_ROW + 1 : 0);
  markCanvasStep("governed text/date/number formats applied");

  try {
    sheet.getRange("A1:D2").setValues([
      ["Master List", "", "", ""],
      ["Date:", monthParts.firstDay, "to", monthParts.lastDay]
    ]);
    markCanvasStep("title/date values stamped");
    if (headers.length) sheet.getRange(HEADER_ROW, 1, 1, width).setValues([headers]);
    markCanvasStep("header values stamped");
    sheet.setFrozenRows(template.getFrozenRows());
    markCanvasStep("frozen rows applied");
    sheet.setFrozenColumns(Math.min(template.getFrozenColumns(), width));
    markCanvasStep("frozen columns applied");
    sheet.setTabColor(template.getTabColor());
    markCanvasStep("tab color applied");
  } catch (err) {
    logBestEffortWarning_("Master List naked canvas initialization skipped: " + err.message);
  }

  clearSheetRuntimeCachesForSheet_(sheet);
  markCanvasStep("runtime caches cleared");
  return sheet;
}

function writeMasterListTitleDateBlock_(masterSheet, monthParts) {
  masterSheet.getRange("A1:D2").setValues([
    ["Master List", "", "", ""],
