  ];
}

function lockSystemTemplateTailBlockOrder_(ss) {
  ss = ss || SpreadsheetApp.getActiveSpreadsheet();
  const tailSheets = getSystemTemplateTailBlockNames_()
    .map(function(name) { return ss.getSheetByName(name); })
    .filter(function(sheet) { return !!sheet; });
  if (!tailSheets.length) return 0;

  let moves = 0;
  tailSheets.forEach(function(sheet, index) {
    const targetPosition = ss.getSheets().length - tailSheets.length + index + 1;
    const wasHidden = typeof sheet.isSheetHidden === "function" && sheet.isSheetHidden();
    try {
      if (sheet.getIndex() !== targetPosition) {
        if (wasHidden) sheet.showSheet();
        ss.setActiveSheet(sheet);
        ss.moveActiveSheet(targetPosition);
        moves++;
      }
      if (wasHidden && !sheet.isSheetHidden()) sheet.hideSheet();
    } catch (err) {
      logBestEffortWarning_("System/template tail-block rank lock skipped for " + sheet.getName() + ": " + err.message);
      try {
        if (wasHidden && !sheet.isSheetHidden()) sheet.hideSheet();
      } catch (hideErr) {
        logBestEffortWarning_("System/template tail-block visibility restore skipped for " + sheet.getName() + ": " + hideErr.message);
      }
    }
  });
  return moves;
}

function lockFrameworkTimingReportAsFinalSheet_(ss) {
  return lockSystemTemplateTailBlockOrder_(ss) > 0;
}

function enforceOperationalSheetSortOrder_(monthParts) {
  const ss = SpreadsheetApp.getActiveSpreadsheet();
  const currentParts = monthParts || getMonthDateParts_(new Date());
  const currentFirst = currentParts && currentParts.firstDay ? currentParts.firstDay : null;

  function name_(sheet) {
    return String(sheet.getName() || "").trim();
  }

  function dateRank_(sheet) {
    const date = extractFirstDateFromSheetName_(name_(sheet));
    if (!date) return 0;
    if (currentFirst && date.getTime() === currentFirst.getTime()) return -9999999999999;
    return -date.getTime();
  }

  const orderedSheets = ss.getSheets().filter(function(sheet) {
    return isOperationalSheetForSort_(name_(sheet)) && !(typeof sheet.isSheetHidden === "function" && sheet.isSheetHidden());
  }).sort(function(a, b) {
    const rankDiff = getGlobalSheetSortRankByName_(name_(a)) - getGlobalSheetSortRankByName_(name_(b));
    if (rankDiff !== 0) return rankDiff;
    const dateDiff = dateRank_(a) - dateRank_(b);
    if (dateDiff !== 0) return dateDiff;
    return name_(a).localeCompare(name_(b));
  });

  let moves = 0;
  orderedSheets.forEach(function(sheet, idx) {
    const targetPosition = idx + 1;
    try {
      if (sheet.getIndex() !== targetPosition) {
        ss.setActiveSheet(sheet);
        ss.moveActiveSheet(targetPosition);
        moves++;
      }
    } catch (err) {
      logBestEffortWarning_("Operational sheet sort skipped for " + name_(sheet) + ": " + err.message);
    }
  });
  try {
    const archiveTarget = ss.getSheetByName(DEMO_P_ARCHIVE_SHEET) || ss.getSheetByName("Archive - Demo P");
    if (archiveTarget && typeof archiveTarget.isSheetHidden === "function" && !archiveTarget.isSheetHidden()) {
      archiveTarget.hideSheet();
    }
  } catch (err) {
    logBestEffortWarning_("Archive tab structural visibility suppression skipped: " + err.message);
  }

  if (lockFrameworkTimingReportAsFinalSheet_(ss)) moves++;
  clearMonthlySheetLookupCache_();
  return moves;
}

function enforceGlobalSheetSortOrder_(monthParts) {
  const ss = SpreadsheetApp.getActiveSpreadsheet();
  const currentParts = monthParts || getMonthDateParts_(new Date());
  const currentFirst = currentParts && currentParts.firstDay ? currentParts.firstDay : null;

  function name_(sheet) {
    return String(sheet.getName() || "").trim();
  }

  function rank_(sheet) {
    return getGlobalSheetSortRankByName_(name_(sheet));
  }

  function dateRank_(sheet) {
    const date = extractFirstDateFromSheetName_(name_(sheet));
    if (!date) return 0;
    if (currentFirst && date.getTime() === currentFirst.getTime()) return -9999999999999;
    return -date.getTime();
  }

  const visibilityByName = {};
  ss.getSheets().forEach(function(sheet) {
    visibilityByName[name_(sheet)] = typeof sheet.isSheetHidden === "function" && sheet.isSheetHidden();
  });

  const orderedSheets = ss.getSheets().slice().sort(function(a, b) {
    const aRank = rank_(a);
    const bRank = rank_(b);
    const aImportOrUnformatted = isImportOrUnformattedSheetRank_(aRank);
    const bImportOrUnformatted = isImportOrUnformattedSheetRank_(bRank);
    if (aImportOrUnformatted && bImportOrUnformatted) {
      const dateDiffForImportGroup = dateRank_(a) - dateRank_(b);
      if (dateDiffForImportGroup !== 0) return dateDiffForImportGroup;
    }
    const rankDiff = aRank - bRank;
    if (rankDiff !== 0) return rankDiff;
    const dateDiff = dateRank_(a) - dateRank_(b);
    if (dateDiff !== 0) return dateDiff;
    return name_(a).localeCompare(name_(b));
  });

  const currentOrderNames = ss.getSheets().map(name_).join("|");
  const desiredOrderNames = orderedSheets.map(name_).join("|");
  if (currentOrderNames === desiredOrderNames) {
    return lockFrameworkTimingReportAsFinalSheet_(ss) ? 1 : 0;
  }

  let position = 1;
  let moves = 0;
  const hiddenSheetsShownForMove = [];
  orderedSheets.forEach(function(sheet) {
    const sheetName = name_(sheet);
    try {
      if (sheet.getIndex() !== position) {
        const wasHidden = typeof sheet.isSheetHidden === "function" && sheet.isSheetHidden();
        if (wasHidden) {
          sheet.showSheet();
          hiddenSheetsShownForMove.push(sheet);
        }
        ss.setActiveSheet(sheet);
        ss.moveActiveSheet(position);
        moves++;
      }
      position++;
    } catch (err) {
      logBestEffortWarning_("Global sheet sort skipped for " + sheetName + ": " + err.message);
    }
  });

  hiddenSheetsShownForMove.forEach(function(sheet) {
    const sheetName = name_(sheet);
    try {
      if (visibilityByName[sheetName] === true && !sheet.isSheetHidden()) sheet.hideSheet();
    } catch (err) {
      logBestEffortWarning_("Global sheet sort visibility restore skipped for " + sheetName + ": " + err.message);
    }
  });

  if (lockFrameworkTimingReportAsFinalSheet_(ss)) moves++;
  clearMonthlySheetLookupCache_();
  return moves;
}

function positionSheetInGlobalSortOrder_(sheet) {
  if (!sheet) return false;
  const ss = SpreadsheetApp.getActiveSpreadsheet();
  const targetName = String(sheet.getName() || "").trim();
  const orderedNames = ss.getSheets()
    .map(function(candidate) { return candidate.getName(); })
    .sort(compareSheetNamesByGlobalOrder_);
  const targetPosition = orderedNames.indexOf(targetName) + 1;
  if (targetPosition <= 0 || sheet.getIndex() === targetPosition) return false;
  if (typeof sheet.isSheetHidden === "function" && sheet.isSheetHidden()) return false;
  try {
    ss.setActiveSheet(sheet);
    ss.moveActiveSheet(targetPosition);
    clearMonthlySheetLookupCache_();
    return true;
  } catch (err) {
    logBestEffortWarning_("Sheet positioning skipped for " + targetName + ": " + err.message);
    return false;
  }
}


function extractFirstDateFromSheetName_(sheetName) {
  const text = String(sheetName || "").trim();
  const match = text.match(/(\d{1,2})\.(\d{1,2})\.(\d{2}|\d{4})/);
  if (!match) return null;
  const month = Number(match[1]);
  const day = Number(match[2]);
  let year = Number(match[3]);
  if (year < 100) year += 2000;
  const date = createLocalDateOnly_(year, month - 1, day);
  if (
    date.getFullYear() !== year ||
    date.getMonth() !== month - 1 ||
    date.getDate() !== day
  ) {
    return null;
  }
  return date;
}

