function moveDisenrolledPMRsFromDemoPToExclusion_(demoSheet, monthParts, timing) {
  const result = { pmrsRemoved: 0, rowsRemoved: 0, rowsCopied: 0 };
  const step = function(label) { if (timing) markFrameworkStep_(timing, "Disenrolled move - " + label); };
  if (!demoSheet) return result;

  const ss = SpreadsheetApp.getActiveSpreadsheet();
  let exclusionSheet = ss.getSheetByName(DISENROLLED_EXCLUSION_SHEET);
  if (!exclusionSheet) {
    exclusionSheet = createDisenrolledExclusionSheetFromDashboardTemplate_(ss, monthParts);
  }
  updateDisenrolledExclusionReportDates_(exclusionSheet, monthParts);
  step("exclusion sheet ready: " + exclusionSheet.getName());

  const lastRow = demoSheet.getLastRow();
  const lastCol = demoSheet.getLastColumn();
  if (lastRow < DATA_START_ROW || lastCol < 1) return result;

  const headers = getHeaders_(demoSheet, HEADER_ROW);
  const headerMap = buildHeaderIndexMap_(headers);
  const pmrIdx = getPMRIndex_(headerMap);
  const primaryIdx = headerMap["Primary PMR Row"];
  const disenrollEffectiveIdx = findHeaderIndex_(headerMap, ["Disenrollment Effective Date", "Disenrollment Date", "Date of Death"]);
  const statusIdx = headerMap["Enrollment Status"];

  if (pmrIdx === -1 || primaryIdx === undefined || disenrollEffectiveIdx === -1) {
    logBestEffortWarning_("Surgical disenrollment sweep skipped: missing critical schema headers.");
    return result;
  }

  const existingExclusionData = getDataValues_(exclusionSheet, HEADER_ROW, DATA_START_ROW);
  step("existing exclusion data read | Rows: " + existingExclusionData.values.length);
  const existingPmrSet = new Set();
  const exclusionPmrIdx = existingExclusionData.headerMap ? getPMRIndex_(existingExclusionData.headerMap) : -1;
  if (exclusionPmrIdx !== -1) {
    existingExclusionData.values.forEach(function(row) {
      const p = normalizePMR_(row[exclusionPmrIdx]);
      if (p) existingPmrSet.add(p);
    });
  }

  const demoDataRange = demoSheet.getRange(DATA_START_ROW, 1, lastRow - DATA_START_ROW + 1, lastCol);
  const values = demoDataRange.getValues();
  step("Demo P body bulk read | Rows: " + values.length);
  const workspaceDisenrolledPMRs = new Set();
  const activeReEnrolledPMRs = new Set();

  values.forEach(function(row) {
    const pmr = normalizePMR_(row[pmrIdx]);
    if (!pmr) return;

    const hasDisenrollmentDate = normalizeCompareValue_(row[disenrollEffectiveIdx]) !== "";
    const statusText = statusIdx !== undefined ? String(row[statusIdx] || "").trim().toLowerCase() : "";
    const isExplicitlyActive = statusText === "active" || statusText === "enrolled";

    if (hasDisenrollmentDate && statusText !== "active") {
      workspaceDisenrolledPMRs.add(pmr);
    } else if (existingPmrSet.has(pmr) && (isExplicitlyActive || !hasDisenrollmentDate)) {
      activeReEnrolledPMRs.add(pmr);
    }
  });
  step("Demo P disenrollment scan complete | Disenrolled PMRs: " + workspaceDisenrolledPMRs.size + "; active re-enrolled PMRs: " + activeReEnrolledPMRs.size);

  if (activeReEnrolledPMRs.size > 0 && exclusionPmrIdx !== -1) {
    const exclusionRowsToDelete = [];

    existingExclusionData.values.forEach(function(exRow, exOffset) {
      const exPmr = normalizePMR_(exRow[exclusionPmrIdx]);
      if (exPmr && activeReEnrolledPMRs.has(exPmr)) {
        exclusionRowsToDelete.push(DATA_START_ROW + exOffset);
      }
    });

    if (exclusionRowsToDelete.length > 0) {
      deleteRowNumberBatches_(exclusionSheet, exclusionRowsToDelete);
      step("re-enrolled exclusion rows purged | Rows: " + exclusionRowsToDelete.length);
      logBestEffortWarning_("Re-Enrollment Engine: Surgically purged " + activeReEnrolledPMRs.size + " re-enrolled PMR records from historical Exclusion sheet.");
    }
  }

  if (workspaceDisenrolledPMRs.size === 0) {
    const remainingActiveRows = Math.max(demoSheet.getLastRow(), DATA_START_ROW + 50);
    forceSheetRowCount_(demoSheet, Math.max(remainingActiveRows, 500));
    clearSheetRuntimeCachesForSheet_(demoSheet);
    clearSheetRuntimeCachesForSheet_(exclusionSheet);
    return result;
  }

  const retainedRows = [];
  const rowsToAppendByPMR = new Map();
  let rowsRemoved = 0;

  values.forEach(function(row) {
    const pmr = normalizePMR_(row[pmrIdx]);
    if (!pmr || !workspaceDisenrolledPMRs.has(pmr)) {
      retainedRows.push(normalizeRowToWidth_(row, lastCol));
      return;
    }

    if (!rowsToAppendByPMR.has(pmr)) {
      rowsToAppendByPMR.set(pmr, []);
    }
    rowsToAppendByPMR.get(pmr).push(row);
    rowsRemoved++;
  });

  step("Demo P retained/remove partition complete | Retained rows: " + retainedRows.length + "; rows selected: " + rowsRemoved);
  result.pmrsRemoved = workspaceDisenrolledPMRs.size;
  result.rowsRemoved = rowsRemoved;

  result.rowsCopied = appendDisenrolledDeltasToExclusionSheet_(exclusionSheet, headers, rowsToAppendByPMR, monthParts, timing);
  if (result.rowsCopied !== result.rowsRemoved) {
    throw new Error("Disenrollment stopped before changing Demo P. Rows copied to Disenrolled Exclusion (" + result.rowsCopied + ") did not match rows selected for removal (" + result.rowsRemoved + ").");
  }

  writeDemoPDisenrollmentRetainedBody_(demoSheet, retainedRows, lastCol, timing);

  const remainingActiveRows = Math.max(DATA_START_ROW + retainedRows.length - 1, DATA_START_ROW + 50);
  forceSheetRowCount_(demoSheet, Math.max(remainingActiveRows, 500));
  step("Demo P row count normalized after retained rewrite");

  clearSheetRuntimeCachesForSheet_(demoSheet);
  clearSheetRuntimeCachesForSheet_(exclusionSheet);
  step("runtime caches cleared after disenrollment move");
  return result;
}

function writeDemoPDisenrollmentRetainedBody_(demoSheet, retainedRows, width, timing) {
  const step = function(label) { if (timing) markFrameworkStep_(timing, "Disenrolled move - Demo P retained rewrite - " + label); };
  const normalizedRows = normalizeRowsToWidth_(retainedRows || [], width);
  step("rows normalized | Rows: " + normalizedRows.length);
  const oldBodyRows = Math.max(demoSheet.getLastRow() - DATA_START_ROW + 1, 0);
  const rowsToClear = Math.max(oldBodyRows, normalizedRows.length, 1);
  const colsToClear = Math.max(demoSheet.getLastColumn(), width, 1);

  ensureOutputSheetHasFormattedRows_(demoSheet, DATA_START_ROW + Math.max(normalizedRows.length, 1) - 1, width);
  step("formatted row capacity ensured");
  demoSheet.getRange(DATA_START_ROW, 1, rowsToClear, colsToClear).clearContent();
  step("old Demo P body content cleared | Rows cleared: " + rowsToClear);
  if (normalizedRows.length) {
    demoSheet.getRange(DATA_START_ROW, 1, normalizedRows.length, width).setValues(normalizedRows);
    step("retained Demo P body written | Rows: " + normalizedRows.length);
  } else {
    step("retained Demo P body write skipped - no rows");
  }
}

