function appendDisenrolledDeltasToExclusionSheet_(exclusionSheet, sourceHeaders, rowsToAppendByPMR, monthParts, timing) {
  const step = function(label) { if (timing) markFrameworkStep_(timing, "Disenrolled move - exclusion append - " + label); };
  if (!exclusionSheet) return 0;
  updateDisenrolledExclusionReportDates_(exclusionSheet, monthParts);
  if (!rowsToAppendByPMR || rowsToAppendByPMR.size === 0) return 0;

  const dashboard = loadDashboardConfig_();
  const exclusionHeaders = getHeadersForSheetType_(dashboard, SHEET_TYPE.DISENROLLED_EXCLUSION);
  const sourceHeaderMap = buildHeaderIndexMap_(sourceHeaders || []);
  const sourcePMRIdx = getPMRIndex_(sourceHeaderMap);
  const exclusionHeaderMap = buildHeaderIndexMap_(exclusionHeaders);
  const exclusionPMRIdx = getPMRIndex_(exclusionHeaderMap);
  const exclusionDateIdx = findHeaderIndex_(exclusionHeaderMap, ["Disenrollment Effective Date", "Disenrollment Date", "Date of Death"]);
  const addedIdx = exclusionHeaderMap[DISENROLLED_EXCLUSION_ADDED_HEADER];
  const addedLabel = "Demo P " + (monthParts && monthParts.firstDay ? formatReportDateLabel_(monthParts.firstDay) : "");

  const sourceIndexes = exclusionHeaders.map(function(header) {
    return Object.prototype.hasOwnProperty.call(sourceHeaderMap, header) ? sourceHeaderMap[header] : -1;
  });

  const appendPayload = [];
  rowsToAppendByPMR.forEach(function(rows) {
    (rows || []).forEach(function(sourceRow) {
      if (!sourceRow) return;

      const output = sourceIndexes.map(function(sourceIdx) {
        return sourceIdx === -1 ? "" : sourceRow[sourceIdx];
      });

      if (exclusionPMRIdx >= 0 && sourcePMRIdx >= 0 && !normalizePMR_(output[exclusionPMRIdx])) {
        output[exclusionPMRIdx] = sourceRow[sourcePMRIdx];
      }
      if (addedIdx !== undefined) output[addedIdx] = addedLabel;
      appendPayload.push(output);
    });
  });
  step("append payload built | Rows: " + appendPayload.length);

  if (appendPayload.length === 0) return 0;

  if (exclusionDateIdx !== -1) {
    appendPayload.sort(function(a, b) {
      const dateA = a[exclusionDateIdx] ? new Date(a[exclusionDateIdx]) : new Date(0);
      const dateB = b[exclusionDateIdx] ? new Date(b[exclusionDateIdx]) : new Date(0);
      return dateB - dateA;
    });
    step("append payload sorted newest to oldest");
  }

  const insertStartRow = DATA_START_ROW;
  const width = Math.max(exclusionHeaders.length, 1);

  if (exclusionSheet.getMaxColumns() < width) {
    exclusionSheet.insertColumnsAfter(exclusionSheet.getMaxColumns(), width - exclusionSheet.getMaxColumns());
  }

  exclusionSheet.insertRowsBefore(insertStartRow, appendPayload.length);
  step("rows inserted at top of Disenrolled Exclusion | Rows: " + appendPayload.length);
  const targetRange = exclusionSheet.getRange(insertStartRow, 1, appendPayload.length, width);
  const writeResult = writeDisenrolledAppendPayloadValues_(exclusionSheet, insertStartRow, appendPayload, width);
  step("append payload values written | Rows: " + appendPayload.length + "; Columns written: " + writeResult.columnsWritten + "; Column runs: " + writeResult.runsWritten + "; Blank columns skipped: " + writeResult.blankColumnsSkipped);

  try {
    const formatSourceRow = insertStartRow + appendPayload.length;
    if (formatSourceRow <= exclusionSheet.getMaxRows()) {
      exclusionSheet.getRange(formatSourceRow, 1, 1, width)
        .copyTo(targetRange, SpreadsheetApp.CopyPasteType.PASTE_FORMAT, false);
      step("append payload formatting copied");
    }
  } catch (err) {
    logBestEffortWarning_("Incremental format brush extension skipped: " + err.message);
  }

  lockFinalOutputRowHeights_(exclusionSheet, "Disenrolled Exclusion");
  step("Disenrolled Exclusion row heights locked");
  clearSheetRuntimeCachesForSheet_(exclusionSheet);
  return appendPayload.length;
}

function writeDisenrolledAppendPayloadValues_(sheet, startRow, payload, width) {
  const rowCount = payload ? payload.length : 0;
  const result = {
    columnsWritten: 0,
    runsWritten: 0,
    blankColumnsSkipped: 0
  };
  if (!sheet || rowCount === 0 || width < 1) return result;

  const nonBlankColumns = [];
  for (let col = 0; col < width; col++) {
    let hasValue = false;
    for (let row = 0; row < rowCount; row++) {
      if (normalizeCompareValue_(payload[row][col]) !== "") {
        hasValue = true;
        break;
      }
    }
    if (hasValue) {
      nonBlankColumns.push(col);
    } else {
      result.blankColumnsSkipped++;
    }
  }

  if (nonBlankColumns.length === 0) return result;

  let runStart = nonBlankColumns[0];
  let previous = runStart;
  const flushRun = function(startCol, endCol) {
    const runWidth = endCol - startCol + 1;
    const values = payload.map(function(row) {
      return row.slice(startCol, endCol + 1);
    });
    sheet.getRange(startRow, startCol + 1, rowCount, runWidth).setValues(values);
    result.columnsWritten += runWidth;
    result.runsWritten++;
  };

  for (let i = 1; i < nonBlankColumns.length; i++) {
    const col = nonBlankColumns[i];
    if (col === previous + 1) {
      previous = col;
      continue;
    }
    flushRun(runStart, previous);
    runStart = col;
    previous = col;
  }
  flushRun(runStart, previous);
  return result;
}

function appendDisenrolledPMRBlocksToExclusion_(sourceSheet, sourceHeaders, rowsByPMR, monthParts) {
  if (!rowsByPMR || rowsByPMR.size === 0) return 0;

  const ss = SpreadsheetApp.getActiveSpreadsheet();
  let exclusionSheet = ss.getSheetByName(DISENROLLED_EXCLUSION_SHEET);
  if (!exclusionSheet) {
    exclusionSheet = createDisenrolledExclusionSheetFromDashboardTemplate_(ss, monthParts);
  }

  return appendDisenrolledDeltasToExclusionSheet_(exclusionSheet, sourceHeaders, rowsByPMR, monthParts, null);
}

function createDisenrolledExclusionSheetFromDashboardTemplate_(ss, monthParts) {
  ss = ss || SpreadsheetApp.getActiveSpreadsheet();
  const existing = ss.getSheetByName(DISENROLLED_EXCLUSION_SHEET);
  if (existing) return existing;

  const dashboard = loadDashboardConfig_();
  const sheetDef = getSheetDefinitionByType_(dashboard, SHEET_TYPE.DISENROLLED_EXCLUSION);
  const headers = getHeadersForSheetType_(dashboard, SHEET_TYPE.DISENROLLED_EXCLUSION);
  const template = sheetDef && sheetDef.templateName ? ss.getSheetByName(sheetDef.templateName) : null;
  let sheet;

  if (template) {
    sheet = template.copyTo(ss);
    setUniqueSheetName_(sheet, DISENROLLED_EXCLUSION_SHEET);
    positionSheetInGlobalSortOrder_(sheet);
    showSheetIfNeeded_(sheet, null, null);
  } else {
    sheet = insertGovernedOutputSheet_(ss, DISENROLLED_EXCLUSION_SHEET);
    const width = Math.max(headers.length, 1);
    resizeSheetGrid_(sheet, Math.max(resolveTemplateRowCount_(sheetDef, dashboard.globals), 25), width);
    updateDisenrolledExclusionReportDates_(sheet, monthParts);
    if (headers.length) sheet.getRange(HEADER_ROW, 1, 1, headers.length).setValues([headers]);
    applyDashboardTemplateFormattingToActiveReportSheet_(sheet, dashboard, sheetDef, headers, getBehaviorForSheetType_(dashboard, SHEET_TYPE.DISENROLLED_EXCLUSION), monthParts, monthParts && monthParts.lastDay, "Initialized without template", null);
    logBestEffortWarning_("Template layer missing for Disenrolled Exclusion; initialized persistent sheet from dashboard schema.");
  }

  updateDisenrolledExclusionReportDates_(sheet, monthParts);
  clearSheetRuntimeCachesForSheet_(sheet);
  positionSheetInGlobalSortOrder_(sheet);
  return sheet;
}

function loadDisenrolledExclusionPMRsForPart3_() {
  const ss = SpreadsheetApp.getActiveSpreadsheet();
  const sheet = ss.getSheetByName(DISENROLLED_EXCLUSION_SHEET);
  const pmrs = new Set();
  if (!sheet || sheet.getLastRow() < DATA_START_ROW) return pmrs;
  const lastCol = sheet.getLastColumn();
  const headers = sheet.getRange(HEADER_ROW, 1, 1, lastCol)
    .getValues()[0]
    .map(h => String(h || "").trim());
  const headerMap = buildHeaderIndexMap_(headers);
  const pmrIdx = getPMRIndex_(headerMap);
  if (pmrIdx === -1) return pmrs;
  const values = sheet.getRange(DATA_START_ROW, 1, sheet.getLastRow() - DATA_START_ROW + 1, lastCol).getValues();
  values.forEach(row => {
    const pmr = normalizePMR_(row[pmrIdx]);
    if (pmr) pmrs.add(pmr);
  });
  return pmrs;
}


