function flushStagedDashboardQualitySectionsRows_(sheet, timing) {
  const keys = Object.keys(ML_DASHBOARD_QUALITY_STAGED_BUFFERS_ || {});
  if (!sheet || !keys.length) return;

  const sectionWrites = [];
  keys.forEach(function(sectionKey) {
    const sectionTitle = getDashboardQualitySectionTitleForKey_(sectionKey);
    if (!sectionTitle) return;
    sectionWrites.push({
      title: sectionTitle,
      rows: buildTimestampedDashboardQualitySectionRows_(sectionKey, ML_DASHBOARD_QUALITY_STAGED_BUFFERS_[sectionKey] || [])
    });
  });

  if (sectionWrites.length) {
    replaceDashboardQualitySectionsRows_(sheet, sectionWrites);
    markFrameworkStep_(timing, "Flushed " + sectionWrites.length + " staged Dashboard Quality sections to sheet canvas");
  }
  ML_DASHBOARD_QUALITY_STAGED_BUFFERS_ = {};
}

