function runFrameworkTimed_(processName, callback) {
  if (!isFrameworkTimingEnabled_()) {
    return runWithWorkflowBusyFlag_(processName, function() { return callback(null); });
  }
  const timing = startFrameworkTiming_(processName);

  return runWithWorkflowBusyFlag_(processName, function() {
    try {
      markFrameworkStep_(timing, "Start");
      const result = callback(timing);
      markFrameworkStep_(timing, "Complete");
      writeFrameworkTimingReportBestEffort_(timing);
      return result;
    } catch (err) {
      const detailText = err && err.timingDetails ? err.timingDetails : (err && err.stack ? err.stack : "");
      markFrameworkStep_(timing, "ERROR - " + err.message, detailText);
      writeFrameworkTimingReportBestEffort_(timing);
      throw err;
    }
  });
}

function runWithWorkflowBusyFlag_(processName, callback) {
  const lock = LockService.getDocumentLock();
  if (!lock.tryLock(15000)) {
    const activeProcess = PropertiesService.getDocumentProperties().getProperty(ML_WORKFLOW_BUSY_KEY) || "Another process";
    const msg = "Workflow paused: " + activeProcess + " is currently running. Please wait a moment and try again.";
    notify_(msg);
    throw new Error(msg);
  }

  markWorkflowBusy_(processName);
  try {
    return callback();
  } finally {
    try {
      clearWorkflowBusy_();
      runDeferredIndexRefreshIfNeeded_();
      forceBaseTemplateHidden_();
      clearAllRuntimeCaches_();
    } finally {
      lock.releaseLock();
    }
  }
}

function markWorkflowBusy_(processName) {
  const props = PropertiesService.getDocumentProperties();
  props.setProperty(ML_WORKFLOW_BUSY_KEY, processName || "Framework Workflow");
  props.setProperty(ML_WORKFLOW_BUSY_STARTED_KEY, String(new Date().getTime()));
}

function clearWorkflowBusy_() {
  const props = PropertiesService.getDocumentProperties();
  props.deleteProperty(ML_WORKFLOW_BUSY_KEY);
  props.deleteProperty(ML_WORKFLOW_BUSY_STARTED_KEY);
}

function runDeferredIndexRefreshIfNeeded_() {
  const props = PropertiesService.getDocumentProperties();
  if (props.getProperty(ML_INDEX_REFRESH_DEFERRED_KEY) !== "true") return false;
  props.deleteProperty(ML_INDEX_REFRESH_DEFERRED_KEY);
  createIndexSheet();
  return true;
}

function startFrameworkTiming_(processName) {
  const now = new Date().getTime();
  return {
    processName: processName,
    startTime: new Date(),
    startMs: now,
    lastMs: now,
    steps: []
  };
}

function markFrameworkStep_(timing, stepName, details) {
  if (!timing) return;

  const normalizedStepName = stepName || "Step";
  if (Object.prototype.hasOwnProperty.call(timing, "warnings") || Object.prototype.hasOwnProperty.call(timing, "monthParts")) {
    markRuntimeStep_(timing, normalizedStepName, details || "");
    return;
  }

  const now = new Date().getTime();
  const stepSeconds = (now - timing.lastMs) / 1000;
  const totalSeconds = (now - timing.startMs) / 1000;
  const severity = /^ERROR\b/i.test(String(normalizedStepName)) ? "CRITICAL" : getRuntimeTimingSeverity_(stepSeconds);
  timing.steps.push({
    processName: timing.processName,
    stepName: normalizedStepName,
    stepSeconds: stepSeconds,
    totalSeconds: totalSeconds,
    timestamp: new Date(),
    severity: severity,
    details: details || ""
  });
  timing.lastMs = now;
}

function writeFrameworkTimingReport_(timing) {
  writeFrameworkTimingReportBestEffort_(timing);
}

function writeFrameworkTimingReportBestEffort_(timing) {
  if (!timing) return false;
  try {
    appendRuntimeTimingToFrameworkTimingReport_(timing);
    writeCombinedFrameworkTimingReport_();
    return true;
  } catch (err) {
    logBestEffortWarning_("Framework timing telemetry skipped for " + String(timing.processName || "process") + ": " + err.message);
    return false;
  }
}

function writeTimingReport_(timing) {
  writeFrameworkTimingReport_(timing);
}

function rebuildProductionMonthlyChangeTemplate() {
  const ss = SpreadsheetApp.getActiveSpreadsheet();
  const dashboard = loadDashboardConfig_();
  const globals = dashboard.globals || {};
  const sheetDef = getSheetDefinitionByType_(dashboard, SHEET_TYPE.MONTHLY_CHANGE);
  if (!sheetDef) return notify_("Error: Monthly Change sheet definition not found in dashboard.");

  const templateName = sheetDef.templateName;
  let template = ss.getSheetByName(templateName);
  if (template) deleteSheetSafely_(ss, template, "Monthly Change template rebuild");

  const rawHeaders = getHeadersForSheetType_(dashboard, SHEET_TYPE.RAW_DATA);
  const reportHeaders = getMonthlyChangeReportHeaders_(rawHeaders);
  const lastCol = Math.max(reportHeaders.length, 1);
  const theme = getThemeColorsFromBase_(sheetDef.baseColor || "#A165CC", globals);

  template = insertGovernedOutputSheet_(ss, templateName);
  resizeSheetGrid_(template, 250, lastCol);

  // Clear format block to preserve base plain text structures
  template.getRange(1, 1, 250, lastCol)
    .setFontFamily(globals.standardFont || "Arial")
    .setFontSize(Number(globals.standardFontSize || 10))
    .setFontColor(globals.standardFontColor || "#000000")
    .setFontWeight("normal")
    .setWrapStrategy(SpreadsheetApp.WrapStrategy.CLIP)
    .setHorizontalAlignment("left")
    .setVerticalAlignment("middle")
    .setBackground("#FFFFFF");

  // Force strict structural text formats on text fields to kill decimal format pollution (0.######).
  applyGovernedTextAndNumberFormats_(template, dashboard, reportHeaders, DATA_START_ROW, 250 - DATA_START_ROW + 1);

  // Re-apply governed subheader layers
  template.getRange(1, 1, 1, lastCol).setBackground(theme.level3);
  template.getRange(2, 1, 1, lastCol).setBackground(theme.level3);
  template.getRange(3, 1, 1, lastCol).setBackground(theme.level1);
  template.getRange(4, 1, 1, lastCol).setBackground(theme.level2);

  template.getRange("A1").setValue("Monthly Change Report").setFontSize(Number(globals.titleFontSize || 14)).setFontWeight("bold");
  template.getRange("A2").setValue("Date");
  template.getRange("C2").setValue("to").setHorizontalAlignment("center");

  const mainHeaderRange = template.getRange(4, 1, 1, lastCol);
  mainHeaderRange.setFontSize(Number(globals.standardFontSize || 10)).setFontWeight("bold").setWrapStrategy(SpreadsheetApp.WrapStrategy.WRAP).setVerticalAlignment("top");
  if (reportHeaders.length) mainHeaderRange.setValues([reportHeaders]);

  safeSetRowHeights_(template, 1, 1, 25);
  safeSetRowHeights_(template, 2, 1, 25);
  safeSetRowHeights_(template, 3, 1, 10);
  safeSetRowHeights_(template, 4, 1, 40);

  const sections = ["Enrollments", "Disenrollments", "Demographic Changes", "Caseload Changes", "Contact Changes", "Banner Summary Changes"];
  let currentRow = 5;

  sections.forEach(function(titleText) {
    template.getRange(currentRow, 1, 1, lastCol).setBackground(theme.level3).setFontWeight("bold");
    template.getRange(currentRow, 1).setValue(titleText).setFontSize(Number(globals.titleFontSize || 14));
    safeSetRowHeights_(template, currentRow, 1, 25);

    template.getRange(currentRow + 1, 1, 1, lastCol).setBackground(theme.level1);
    safeSetRowHeights_(template, currentRow + 1, 1, 7);

    const line3Range = template.getRange(currentRow + 2, 1, 1, lastCol);
    line3Range.setFontSize(Number(globals.standardFontSize || 10)).setFontWeight("bold").setWrapStrategy(SpreadsheetApp.WrapStrategy.WRAP).setVerticalAlignment("top").setBackground(theme.level2);
    if (reportHeaders.length) line3Range.setValues([reportHeaders]);
    safeSetRowHeights_(template, currentRow + 2, 1, 10);

    template.getRange(currentRow + 3, 1, 1, lastCol).setBackground("#FFFFFF");
    safeSetRowHeights_(template, currentRow + 3, 1, 25);

    currentRow += 8;
  });

  template.setFrozenRows(4);
  template.setFrozenColumns(2);
  template.setTabColor(theme.level1);
  template.hideSheet();
  notify_("SUCCESS: Monthly Change Template sanitized and text-shielded.");
}
